const MIN_SIZE = 30 * 1024; // 50 KB

function sizeToBytes(sizeText) {
  if (sizeText == null) return 0;
  const s = String(sizeText).trim();

  // supports: "32.2 kB", "1.72 MB", "512 B", "2 GB"
  const m = s.match(/^([\d.]+)\s*([KMGTP]?B)$/i);
  if (!m) return Number(s) || 0;

  const value = Number(m[1]);
  const unit = m[2].toUpperCase();

  const mult = {
    B: 1,
    KB: 1024,
    MB: 1024 ** 2,
    GB: 1024 ** 3,
    TB: 1024 ** 4,
    PB: 1024 ** 5,
  }[unit] ?? 1;

  return Math.round(value * mult);
}

const out = [];

for (const item of $input.all()) {
  const bins = item.binary ?? {};
  const json = item.json ?? {};

  for (const [k, file] of Object.entries(bins)) {
    const bytes = sizeToBytes(file.fileSize); // if fileSize is "32.2 kB"

    console.log(file.fileName, file.fileSize, bytes);
    if (bytes < MIN_SIZE) continue;

    out.push({
      json: {
        ...json,
        fileName: file.fileName,
        fileSize: bytes,
        mimeType: file.mimeType,
      },
      binary: { data: file },
    });
  }
}

return out;

